// src/core/phaser/scaleManager.ts
import Phaser from "phaser";

export type DesignSize = { width: number; height: number };

export type SafeAreaInsets = {
  top: number;
  right: number;
  bottom: number;
  left: number;
};

export type ScaleSnapshot = {
  container: { width: number; height: number; dpr: number };
  safeArea: SafeAreaInsets;
  design: DesignSize;
  scale: number;
  // vùng "game content" (đã FIT + trừ safe-area + letterbox)
  viewport: { x: number; y: number; width: number; height: number };
};

export type ScaleManagerOptions = {
  design: DesignSize;

  /** clamp dpr để không quá nặng GPU trên mobile */
  maxDpr?: number; // default 2

  /**
   * Safe-area strategy:
   * - "css-vars": đọc từ CSS vars (--safe-area-inset-*)
   * - "none": coi như 0
   */
  safeAreaMode?: "css-vars" | "none";

  /** Có vẽ khung debug viewport/safearea không */
  debug?: boolean;

  /** Gọi khi snapshot thay đổi */
  onChange?: (snap: ScaleSnapshot) => void;
};

/**
 * ScaleManager theo kiểu "FIT + letterbox + safe-area":
 * - Không đổi world size (vẫn là design width/height)
 * - Canvas/camera scale để fit vào viewport
 * - Cung cấp snapshot (scale, viewport, safeArea) để layout UI chuẩn
 */
export class ScaleManager {
  private scene: Phaser.Scene;
  private opts: Required<Omit<ScaleManagerOptions, "onChange">> & {
    onChange?: (snap: ScaleSnapshot) => void;
  };

  private graphics?: Phaser.GameObjects.Graphics;
  private lastSnap?: ScaleSnapshot;

  constructor(scene: Phaser.Scene, options: ScaleManagerOptions) {
    this.scene = scene;
    this.opts = {
      design: options.design,
      maxDpr: options.maxDpr ?? 2,
      safeAreaMode: options.safeAreaMode ?? "css-vars",
      debug: options.debug ?? false,
      onChange: options.onChange,
    };

    if (this.opts.debug) {
      this.graphics = scene.add.graphics().setDepth(999999);
    }
  }

  /** gọi 1 lần trong create() */
  initFromWindow() {
    const w = window.innerWidth;
    const h = window.innerHeight;
    const dpr = window.devicePixelRatio || 1;
    this.applyResize({ width: w, height: h, dpr });
  }

  /** gọi khi hub gửi RESIZE */
  applyResize(input: { width: number; height: number; dpr?: number }) {
    const dpr = clampDpr(
      input.dpr ?? window.devicePixelRatio ?? 1,
      this.opts.maxDpr
    );

    const game = this.scene.game;

    // Phaser 3: ép renderer resolution (giảm DPR thực sự)
    if (game.renderer && "resolution" in game.renderer) {
      // @ts-ignore
      game.renderer.resolution = dpr;
    }

    // Phaser ScaleManager: resize canvas to container size rồi refresh
    // (works tốt khi game config scale.mode = Phaser.Scale.NONE hoặc RESIZE)
    // Nếu bạn dùng FIT trong config, vẫn nên gọi resize+refresh để cập nhật parent bounds.
    this.scene.scale.resize(input.width, input.height);
    this.scene.scale.refresh();

    const safeArea =
      this.opts.safeAreaMode === "css-vars"
        ? readSafeAreaCssVars()
        : zeroInsets();

    const snap = computeFitSnapshot({
      container: { width: input.width, height: input.height, dpr },
      design: this.opts.design,
      safeArea,
    });

    this.applyCameraFit(snap);

    if (!this.lastSnap || !snapEquals(this.lastSnap, snap)) {
      this.lastSnap = snap;
      if (this.opts.debug) this.drawDebug(snap);
      this.opts.onChange?.(snap);
      // emit event cho scene/game nếu muốn nghe
      this.scene.events.emit("scale:snapshot", snap);
    }
  }

  /** snapshot mới nhất */
  getSnapshot(): ScaleSnapshot {
    if (!this.lastSnap) {
      // fallback
      return computeFitSnapshot({
        container: {
          width: this.scene.scale.width,
          height: this.scene.scale.height,
          dpr: clampDpr(window.devicePixelRatio || 1, this.opts.maxDpr),
        },
        design: this.opts.design,
        safeArea:
          this.opts.safeAreaMode === "css-vars"
            ? readSafeAreaCssVars()
            : zeroInsets(),
      });
    }
    return this.lastSnap;
  }

  /** tiện: trả viewport rect (nơi nên đặt UI) */
  getViewport() {
    return this.getSnapshot().viewport;
  }

  /** tiện: trả safeArea */
  getSafeArea() {
    return this.getSnapshot().safeArea;
  }

  /**
   * Quy ước:
   * - World size = design (0..designW, 0..designH)
   * - Camera zoom = snap.scale
   * - Camera scroll để world center vào viewport
   */
  private applyCameraFit(snap: ScaleSnapshot) {
    const cam = this.scene.cameras.main;

    // set viewport theo pixel canvas
    cam.setViewport(
      snap.viewport.x,
      snap.viewport.y,
      snap.viewport.width,
      snap.viewport.height
    );

    // world size cố định: design size
    cam.setBounds(0, 0, snap.design.width, snap.design.height);

    // Fit: zoom theo scale
    cam.setZoom(snap.scale);

    // Center camera on world center
    cam.centerOn(snap.design.width / 2, snap.design.height / 2);
  }

  private drawDebug(snap: ScaleSnapshot) {
    if (!this.graphics) return;
    const g = this.graphics;
    g.clear();

    // safe area box = container trừ insets
    const safeX = snap.safeArea.left;
    const safeY = snap.safeArea.top;
    const safeW =
      snap.container.width - snap.safeArea.left - snap.safeArea.right;
    const safeH =
      snap.container.height - snap.safeArea.top - snap.safeArea.bottom;

    // vẽ safe area
    g.lineStyle(2, 0x00ff00, 1);
    g.strokeRect(safeX, safeY, safeW, safeH);

    // vẽ viewport
    g.lineStyle(2, 0xff00ff, 1);
    g.strokeRect(
      snap.viewport.x,
      snap.viewport.y,
      snap.viewport.width,
      snap.viewport.height
    );
  }
}

/** helper create */
export function createScaleManager(
  scene: Phaser.Scene,
  options: ScaleManagerOptions
) {
  return new ScaleManager(scene, options);
}

// ---------------- internals ----------------

function clampDpr(dpr: number, maxDpr: number) {
  const n = Number.isFinite(dpr) ? dpr : 1;
  return Math.max(1, Math.min(maxDpr, n));
}

function zeroInsets(): SafeAreaInsets {
  return { top: 0, right: 0, bottom: 0, left: 0 };
}

/**
 * Đọc safe-area từ CSS vars (bạn set trong global css):
 * :root{
 *   --safe-area-inset-top: env(safe-area-inset-top);
 *   --safe-area-inset-right: env(safe-area-inset-right);
 *   --safe-area-inset-bottom: env(safe-area-inset-bottom);
 *   --safe-area-inset-left: env(safe-area-inset-left);
 * }
 */
function readSafeAreaCssVars(): SafeAreaInsets {
  const s = getComputedStyle(document.documentElement);
  const top = parseCssPx(s.getPropertyValue("--safe-area-inset-top"));
  const right = parseCssPx(s.getPropertyValue("--safe-area-inset-right"));
  const bottom = parseCssPx(s.getPropertyValue("--safe-area-inset-bottom"));
  const left = parseCssPx(s.getPropertyValue("--safe-area-inset-left"));
  return { top, right, bottom, left };
}

function parseCssPx(v: string): number {
  const n = parseFloat(String(v).trim().replace("px", ""));
  return Number.isFinite(n) ? n : 0;
}

function computeFitSnapshot(args: {
  container: { width: number; height: number; dpr: number };
  design: DesignSize;
  safeArea: SafeAreaInsets;
}): ScaleSnapshot {
  const { container, design, safeArea } = args;

  const safeW = Math.max(1, container.width - safeArea.left - safeArea.right);
  const safeH = Math.max(1, container.height - safeArea.top - safeArea.bottom);

  const scale = Math.min(safeW / design.width, safeH / design.height);

  const viewW = Math.round(design.width * scale);
  const viewH = Math.round(design.height * scale);

  const x = Math.round(safeArea.left + (safeW - viewW) / 2);
  const y = Math.round(safeArea.top + (safeH - viewH) / 2);

  return {
    container,
    safeArea,
    design,
    scale,
    viewport: { x, y, width: viewW, height: viewH },
  };
}

function snapEquals(a: ScaleSnapshot, b: ScaleSnapshot) {
  return (
    a.container.width === b.container.width &&
    a.container.height === b.container.height &&
    a.safeArea.top === b.safeArea.top &&
    a.safeArea.right === b.safeArea.right &&
    a.safeArea.bottom === b.safeArea.bottom &&
    a.safeArea.left === b.safeArea.left &&
    Math.abs(a.scale - b.scale) < 1e-6 &&
    a.viewport.x === b.viewport.x &&
    a.viewport.y === b.viewport.y &&
    a.viewport.width === b.viewport.width &&
    a.viewport.height === b.viewport.height
  );
}
