import { NormalizedSubmitBody, RawResult } from "../contract/types";

export interface ConversionResult {
  fields: Partial<NormalizedSubmitBody>;
  warnings: string[];
}

export function convertQuiz(raw: RawResult): ConversionResult {
  const warnings: string[] = [];
  const result: Partial<NormalizedSubmitBody> = {};

  // Standard Quiz fields: correctCount, totalQuestions
  const correct =
    typeof raw.correctCount === "number" ? raw.correctCount : undefined;
  const total =
    typeof raw.totalQuestions === "number" ? raw.totalQuestions : undefined;

  if (correct !== undefined && total !== undefined && total > 0) {
    result.accuracy = correct / total;
    result.completion = 1; // Assuming submission means done? Or check answered count?
    // If raw has answeredCount, use that.
    const answered =
      typeof raw.answeredCount === "number" ? raw.answeredCount : total;
    result.completion = answered / total;
  } else {
    // Try to infer from score?
    if (
      typeof raw.score === "number" &&
      typeof raw.maxScore === "number" &&
      raw.maxScore > 0
    ) {
      result.accuracy = raw.score / raw.maxScore;
    }
  }

  return { fields: result, warnings };
}
