export enum ErrorCode {
  // Lỗi hệ thống (System)
  SYS_INIT_TIMEOUT = "SYS:INIT_TIMEOUT", // Mạng lag, không bắt tay được
  SYS_INVALID_CONTEXT = "SYS:INVALID_CONTEXT", // BE gửi data sai
  SYS_CONNECTION_LOST = "SYS:CONNECTION_LOST",

  // Lỗi từ Game (Game)
  GAME_CRASH = "GAME:CRASH", // Game code bị bug
  GAME_ASSET_FAIL = "GAME:ASSET_FAIL", // Không tải được ảnh/nhạc

  // Lỗi Dữ liệu (Data)
  DATA_VALIDATION_FAIL = "DATA:INVALID", // Gửi điểm số sai format
}

export class SdkError extends Error {
  constructor(public code: ErrorCode, message: string, public details?: any) {
    super(message);
    this.name = "SdkError";
  }
}
