import { MessageType, MsgEnvelope } from "../protocol";
import type { LaunchContext } from "../contract/types";

export class HandshakeHubBridge {
  private iframeWindow: Window;
  private context: LaunchContext;
  private isGameReady = false;
  private targetOrigin: string;

  constructor(
    iframeWindow: Window,
    context: LaunchContext,
    targetOrigin = "*"
  ) {
    this.iframeWindow = iframeWindow;
    this.context = context;
    this.targetOrigin = targetOrigin;
    this.setupListener();
  }

  private setupListener() {
    window.addEventListener("message", (event) => {
      // Validate origin if needed
      if (this.targetOrigin !== "*" && event.origin !== this.targetOrigin) {
        return;
      }

      const data = event.data as MsgEnvelope;

      if (data?.source !== "game") return;

      switch (data.type) {
        case MessageType.HELLO:
          this.handleGameHello();
          break;
        case MessageType.READY:
          this.handleGameReady();
          break;
        // Handle other events: SCORE_UPDATE, COMPLETE, etc.
        // These can be extended based on your needs
      }
    });
  }

  private handleGameHello() {
    // Game just said "I'm here!", Hub responds with "Here's your context"
    // Hub may receive multiple HELLO messages (Game sends continuously),
    // but sending INIT multiple times is safe (idempotent).

    const envelope: MsgEnvelope<LaunchContext> = {
      source: "hub",
      type: MessageType.INIT,
      payload: this.context,
      sdkVersion: "1.0.0",
      sessionId: this.context.sessionId,
      gameId: this.context.gameId,
      lessonId: this.context.lessonId,
      gameVersion: this.context.gameVersion,
    };

    console.log("[HubSDK] Sending INIT to Game");
    this.iframeWindow.postMessage(envelope, this.targetOrigin);
  }

  private handleGameReady() {
    this.isGameReady = true;
    console.log("[HubSDK] Game is fully READY");
    // You can hide loading bar here or trigger other UI updates
  }

  // -------------------- Game Control Methods --------------------

  public init(context: LaunchContext) {
    this.context = context;
    // Send INIT immediately if needed
  }

  public pause() {
    this.send(MessageType.PAUSE);
  }

  public resume() {
    this.send(MessageType.RESUME);
  }

  public start() {
    this.send(MessageType.START);
  }

  public quit() {
    this.send(MessageType.QUIT);
  }

  public resize(width: number, height: number, dpr = 1) {
    this.send(MessageType.RESIZE, { width, height, dpr });
  }

  public setState(state: any) {
    this.send(MessageType.SET_STATE, state);
  }

  public dispose() {
    // Cleanup method for compatibility
  }

  public getGameReadyStatus(): boolean {
    return this.isGameReady;
  }

  private send(type: string, payload?: any) {
    const envelope: MsgEnvelope = {
      source: "hub",
      type,
      payload,
      sdkVersion: "1.0.0",
      sessionId: this.context.sessionId,
      gameId: this.context.gameId,
      lessonId: this.context.lessonId,
      gameVersion: this.context.gameVersion,
    };

    this.iframeWindow.postMessage(envelope, this.targetOrigin);
  }
}

// Compatibility function for apps
export function createHubBridge(
  config: { iframe: HTMLIFrameElement; targetOrigin: string },
  _onEvent: (event: any) => void
): HandshakeHubBridge {
  const dummyContext: LaunchContext = {
    sessionId: "dummy",
    gameId: "dummy",
    mode: "dev" as const,
    locale: "vi",
    difficulty: "medium" as const,
    player: { name: "Student" },
    soundEnabled: true
  };
  
  return new HandshakeHubBridge(
    config.iframe.contentWindow!,
    dummyContext,
    config.targetOrigin
  );
}
