// src/core/phaser/HowlerAudioManager.ts
import { Howl, Howler } from "howler";

export type AudioKind = "bgm" | "voice" | "sfx";
export type AudioFormat = "m4a" | "mp3" | "ogg" | "wav";

export type AudioAsset = {
  key: string;
  kind: AudioKind;

  // cho phép 1 trong 2
  src?: string[]; // explicit sources
  basePath?: string; // "/assets/audio/bgm_1"
  exts?: AudioFormat[]; // ["m4a","mp3","ogg"]

  volume?: number;
  loop?: boolean;
  preload?: boolean;
  rate?: number;
  crossOrigin?: "anonymous" | "use-credentials" | "";
  probe?: boolean;
  probeTimeoutMs?: number;
};

export type AudioManagerOptions = {
  groupVolume?: Partial<Record<AudioKind, number>>;
  duckBgmTo?: number;
  fadeMs?: number;
  debug?: boolean;
  onState?: (s: { unlocked: boolean; muted: boolean }) => void;

  /** default cho probe trong register() */
  defaultProbe?: boolean; // default true
  defaultProbeTimeoutMs?: number; // default 1200
};

type Track = {
  asset: AudioAsset;
  howl: Howl;
};

export class HowlerAudioManager {
  private tracks = new Map<string, Track>();

  private unlocked = false;
  private muted = false;

  private bgmKey: string | null = null;
  private voiceKey: string | null = null;

  private pendingPlays: Array<() => void> = [];
  private queueUntilUnlock = true;

  private opts: Required<Omit<AudioManagerOptions, "onState">> & {
    onState?: AudioManagerOptions["onState"];
  };

  constructor(opts?: AudioManagerOptions) {
    this.opts = {
      groupVolume: {
        bgm: opts?.groupVolume?.bgm ?? 1,
        voice: opts?.groupVolume?.voice ?? 1,
        sfx: opts?.groupVolume?.sfx ?? 1,
      },
      duckBgmTo: opts?.duckBgmTo ?? 0.25,
      fadeMs: opts?.fadeMs ?? 200,
      debug: opts?.debug ?? false,
      onState: opts?.onState,
      defaultProbe: opts?.defaultProbe ?? true,
      defaultProbeTimeoutMs: opts?.defaultProbeTimeoutMs ?? 1200,
    };
  }

  // ---------- registry ----------
  /**
   * Register assets. Supports:
   * - { src: [...] }
   * - { basePath, exts }  (auto build + optional probe)
   */
  async register(assets: AudioAsset[]) {
    for (const a of assets) {
      if (this.tracks.has(a.key)) continue;

      const src = await this.resolveSrc(a);
      if (!src.length) {
        this.d("[audio] no valid src resolved for", a.key);
        continue;
      }

      const crossOrigin = (a as any).crossOrigin;
      if (crossOrigin) Howler.autoUnlock = true; // helps some browsers

      const howl = new Howl({
        src,
        preload: a.preload ?? true,
        loop: a.loop ?? false,
        volume: this.computeTrackVolume(a),
        rate: a.rate ?? 1,
        html5: a.kind === "bgm",
      });
      this.tracks.set(a.key, { asset: a, howl });
    }
  }

  has(key: string) {
    return this.tracks.has(key);
  }

  async loadAll(opts?: {
    strict?: boolean;
    onProgress?: (p: { loaded: number; total: number }) => void;
  }) {
    const strict = opts?.strict ?? false;

    const entries = [...this.tracks.entries()];
    const total = entries.length;
    let loaded = 0;

    const results = await Promise.all(
      entries.map(([key, t]) => {
        return new Promise<{ key: string; ok: boolean; err?: any }>(
          (resolve) => {
            const done = (ok: boolean, err?: any) => {
              loaded += 1;
              opts?.onProgress?.({ loaded, total });
              resolve({ key, ok, err });
            };

            // already loaded
            if (t.howl.state() === "loaded") return done(true);

            t.howl.once("load", () => done(true));
            t.howl.once("loaderror", (_id, err) => done(false, err));

            try {
              t.howl.load();
            } catch (e) {
              done(false, e);
            }
          }
        );
      })
    );

    const failed = results.filter((r) => !r.ok);
    if (strict && failed.length) {
      throw new Error(
        `AUDIO_LOAD_FAIL: ${failed.map((f) => f.key).join(", ")}`
      );
    }
  }

  // ---------- unlock ----------
  async unlock(): Promise<boolean> {
    if (this.unlocked) return true;

    try {
      const ctx = Howler.ctx;
      if (ctx && ctx.state === "suspended") await ctx.resume();

      const silent = new Howl({
        src: [
          "data:audio/mp3;base64,//uQxAAAAAAAAAAAAAAAAAAAAAAAWGluZwAAAA8AAAACAAACcQCA",
        ],
        volume: 0,
      });
      silent.play();
      silent.stop();

      this.unlocked = true;
      this.emitState();
      this.d("[audio] unlocked");

      // flush pending plays NGAY sau khi unlock
      const plays = [...this.pendingPlays];
      this.pendingPlays = [];
      plays.forEach((fn) => {
        try {
          fn();
        } catch {}
      });

      return true;
    } catch (e) {
      this.d("[audio] unlock failed", e);
      return false;
    }
  }

  bindUnlockToGesture(target: HTMLElement | Document = document) {
    const handler = async () => {
      await this.unlock();
      target.removeEventListener("pointerdown", handler as any);
      target.removeEventListener("touchstart", handler as any);
      target.removeEventListener("click", handler as any);
    };

    target.addEventListener("pointerdown", handler as any, {
      passive: true,
      once: true,
    });
    target.addEventListener("touchstart", handler as any, {
      passive: true,
      once: true,
    });
    target.addEventListener("click", handler as any, {
      passive: true,
      once: true,
    });
  }

  // ---------- controls ----------
  setMuted(muted: boolean) {
    this.muted = muted;
    Howler.mute(muted);
    this.emitState();
  }

  isUnlocked() {
    return this.unlocked;
  }

  // ---------- play APIs ----------
  playSfx(key: string) {
    return this.play(key, "sfx");
  }

  playVoice(key: string) {
    return this.play(key, "voice");
  }

  async setBgm(key: string) {
    if (this.bgmKey === key) {
      const t = this.tracks.get(key);
      if (t && !t.howl.playing()) t.howl.play();
      return;
    }

    const prev = this.bgmKey;
    this.bgmKey = key;
    if (prev) this.fadeOutStop(prev);

    const t = this.tracks.get(key);
    if (!t) return;

    t.howl.volume(0);
    t.howl.loop(true);
    t.howl.play();
    this.fadeTo(key, this.computeTrackVolume(t.asset), this.opts.fadeMs);
  }

  stopBgm() {
    if (!this.bgmKey) return;
    this.fadeOutStop(this.bgmKey);
    this.bgmKey = null;
  }

  stopAllVoices() {
    for (const [_key, t] of this.tracks.entries()) {
      if (t.asset.kind === "voice") {
        try {
          t.howl.stop();
        } catch {}
      }
    }
    if (this.voiceKey) this.voiceKey = null;
    this.duckBgm(false);
  }

  stopAll() {
    for (const [key] of this.tracks) this.stop(key);
    this.bgmKey = null;
    this.voiceKey = null;
  }

  pauseAll() {
    for (const t of this.tracks.values()) {
      if (t.howl.playing()) t.howl.pause();
    }
  }

  resumeAll() {
    if (this.bgmKey) {
      const t = this.tracks.get(this.bgmKey);
      if (t && !t.howl.playing()) t.howl.play();
    }
    if (this.voiceKey) {
      const t = this.tracks.get(this.voiceKey);
      if (t && !t.howl.playing()) t.howl.play();
    }
  }

  // ---------- internals ----------
  private async resolveSrc(a: AudioAsset): Promise<string[]> {
    if (a.src?.length) return a.src;

    if (!a.basePath) return [];

    const exts = a.exts ?? ["m4a", "mp3", "ogg"];
    const urls = exts.map((ext) => `${a.basePath}.${ext}`);

    const probe = a.probe ?? this.opts.defaultProbe;
    if (!probe) return urls;

    const timeout = a.probeTimeoutMs ?? this.opts.defaultProbeTimeoutMs;
    const existed = await filterExistingUrls(urls, timeout);
    return existed;
  }

  private play(key: string, kind: AudioKind) {
    const t = this.tracks.get(key);
    if (!t) {
      this.d("[audio] missing:", key);
      return null;
    }

    const doPlay = () => {
      // Voice rules
      if (kind === "voice") {
        if (this.voiceKey && this.voiceKey !== key) this.stop(this.voiceKey);
        this.voiceKey = key;
        this.duckBgm(true);
      }

      t.howl.volume(this.computeTrackVolume(t.asset));
      const id = t.howl.play();

      t.howl.once(
        "end",
        () => {
          if (kind === "voice" && this.voiceKey === key) {
            this.voiceKey = null;
            this.duckBgm(false);
          }
        },
        id
      );

      t.howl.once(
        "stop",
        () => {
          if (kind === "voice" && this.voiceKey === key) {
            this.voiceKey = null;
            this.duckBgm(false);
          }
        },
        id
      );

      return id;
    };

    // chưa unlock thì queue
    if (!this.unlocked && this.queueUntilUnlock) {
      this.pendingPlays.push(doPlay);
      this.d("[audio] queue play until unlock:", key);
      return null;
    }

    return doPlay();
  }

  private stop(key: string) {
    const t = this.tracks.get(key);
    if (!t) return;
    try {
      t.howl.stop();
    } catch {}
  }

  private fadeOutStop(key: string) {
    const t = this.tracks.get(key);
    if (!t) return;
    try {
      const from = t.howl.volume();
      t.howl.fade(from, 0, this.opts.fadeMs);
      window.setTimeout(() => {
        try {
          t.howl.stop();
        } catch {}
        t.howl.volume(this.computeTrackVolume(t.asset));
      }, this.opts.fadeMs + 30);
    } catch {
      this.stop(key);
    }
  }

  private fadeTo(key: string, to: number, ms: number) {
    const t = this.tracks.get(key);
    if (!t) return;
    try {
      const from = t.howl.volume();
      t.howl.fade(from, to, ms);
    } catch {
      t.howl.volume(to);
    }
  }

  private duckBgm(duck: boolean) {
    if (!this.bgmKey) return;
    const t = this.tracks.get(this.bgmKey);
    if (!t) return;

    const normal = this.computeTrackVolume(t.asset);
    const target = duck ? Math.min(normal, this.opts.duckBgmTo) : normal;
    this.fadeTo(this.bgmKey, target, this.opts.fadeMs);
  }

  private computeTrackVolume(a: AudioAsset) {
    const base = (a as any).volume ?? 1;
    const g = this.opts.groupVolume[a.kind] ?? 1;
    return clamp01(base * g);
  }

  private emitState() {
    this.opts.onState?.({ unlocked: this.unlocked, muted: this.muted });
  }

  private d(...args: any[]) {
    if (this.opts.debug) console.log(...args);
  }
}

function clamp01(n: number) {
  return Math.max(0, Math.min(1, n));
}

// ---- probe helpers ----
async function filterExistingUrls(
  urls: string[],
  timeoutMs: number
): Promise<string[]> {
  const ok: string[] = [];
  for (const url of urls) {
    const exists = await headOk(url, timeoutMs);
    if (exists) ok.push(url);
  }
  // nếu HEAD fail hết (server chặn HEAD) -> trả nguyên list để Howler tự thử
  return ok.length ? ok : urls;
}

async function headOk(url: string, timeoutMs: number): Promise<boolean> {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), timeoutMs);
  try {
    const res = await fetch(url, {
      method: "HEAD",
      cache: "no-cache",
      signal: ctrl.signal,
    });
    return res.ok;
  } catch {
    return false;
  } finally {
    clearTimeout(t);
  }
}
