/**
 * Manages game state saving with debouncing to prevent excessive Hub calls.
 */
export class AutoSaveManager {
  private debounceMs: number;
  private pendingState: Record<string, unknown> | null = null;
  private saveTimer: any = null;
  private saveCallback: (state: Record<string, unknown>) => Promise<void>;
  private isSaving = false;

  /**
   * @param saveCallback - Function to persist state to Hub
   * @param debounceMs - Delay in ms before saving (default: 3000ms)
   */
  constructor(
    saveCallback: (state: Record<string, unknown>) => Promise<void>,
    debounceMs = 3000
  ) {
    this.saveCallback = saveCallback;
    this.debounceMs = debounceMs;
  }

  /**
   * Request a save. Will be debounced.
   * @param state - The game state to save
   */
  public requestSave(state: Record<string, unknown>): void {
    this.pendingState = state;

    if (this.saveTimer) {
      clearTimeout(this.saveTimer);
    }

    this.saveTimer = setTimeout(() => {
      this.flush();
    }, this.debounceMs);
  }

  /**
   * Force save immediately if there is pending state.
   * Useful for "onPause" or "onQuit" events.
   */
  public async flush(): Promise<void> {
    if (this.saveTimer) {
      clearTimeout(this.saveTimer);
      this.saveTimer = null;
    }

    if (!this.pendingState) return;

    if (this.isSaving) {
      // If already saving, reschedule flush for later
      this.saveTimer = setTimeout(() => this.flush(), 500);
      return;
    }

    try {
      this.isSaving = true;
      const stateToSave = this.pendingState;
      // Optimistically clear pending state before save
      // so new changes during save are not lost
      this.pendingState = null;

      await this.saveCallback(stateToSave);
      console.debug("[AutoSaveManager] Saved successfully.");
    } catch (err) {
      console.error("[AutoSaveManager] Save failed:", err);
      // Restore pending state if failed, but merge with any new updates?
      // For simplicity, we might lose some updates if we don't merge.
      // But re-saving immediately might cause loop.
    } finally {
      this.isSaving = false;

      // If new changes came in while saving, schedule another flush
      if (this.pendingState) {
        this.requestSave(this.pendingState);
      }
    }
  }
}
