// src/core/runtime/gameSessionUiRuntime.ts
import type { GameSdk } from "../game/gameSdk.v1";
import { ScoreTimer } from "./score/scoreTimer";
import { ScoreTimerHudDom } from "./ui/hudDom";
import { ResultOverlayDom } from "./ui/resultOverlayDom";

export type GameSessionUiRuntimeOptions = {
  sdk: GameSdk;
  /** safe insets: lấy từ ScaleManager nếu có */
  safeInsets?: { top?: number; left?: number; bottom?: number; right?: number };
  /** gọi khi user bấm replay */
  onReplay?: () => void;
  /** gọi khi user bấm exit (thường sẽ trigger COMPLETE nếu chưa) */
  onExit?: () => void;
};

export function createGameSessionUiRuntime(opts: GameSessionUiRuntimeOptions) {
  const timer = new ScoreTimer();

  const hud = new ScoreTimerHudDom({
    safeTop: opts.safeInsets?.top ?? 0,
    safeLeft: opts.safeInsets?.left ?? 0,
  });

  let completed = false;

  const overlay = new ResultOverlayDom({
    safeBottom: opts.safeInsets?.bottom ?? 0,
    onReplay: () => opts.onReplay?.(),
    onExit: () => opts.onExit?.(),
  });

  let raf: number | null = null;
  const tick = () => {
    const snap = timer.snapshot();
    hud.update(snap);
    raf = requestAnimationFrame(tick);
  };

  const start = () => {
    timer.start();
    if (raf == null) raf = requestAnimationFrame(tick);
  };

  const pause = () => timer.pause();
  const resume = () => timer.start(); // tiếp tục

  const setScore = (score: number, delta?: number) => {
    timer.setScore(score);
    opts.sdk.score(score, delta);
  };

  const addScore = (delta: number) => {
    timer.addScore(delta);
    opts.sdk.score(timer.getScore(), delta);
  };

  const finish = (extras?: any) => {
    if (completed) return;
    completed = true;

    const snap = timer.snapshot();
    overlay.show(snap);

    opts.sdk.complete({
      score: snap.score,
      timeMs: snap.elapsedMs,
      extras,
    });
  };

  const destroy = () => {
    if (raf != null) cancelAnimationFrame(raf);
    raf = null;
    hud.destroy();
    overlay.destroy();
  };

  return {
    timer,
    hud,
    overlay,
    start,
    pause,
    resume,
    setScore,
    addScore,
    finish,
    destroy,
  };
}
