// src/core/runtime/ui/resultOverlayDom.ts
import { ScoreTimer } from "../score/scoreTimer";

export type ResultOverlayOptions = {
  mount?: HTMLElement;
  zIndex?: number;
  safeBottom?: number;
  onReplay?: () => void;
  onExit?: () => void;
};

export class ResultOverlayDom {
  private root: HTMLDivElement;
  // private box: HTMLDivElement;
  private scoreEl: HTMLDivElement;
  private timeEl: HTMLDivElement;

  constructor(opts?: ResultOverlayOptions) {
    const mount = opts?.mount ?? document.body;
    const zIndex = opts?.zIndex ?? 10000;
    const safeBottom = opts?.safeBottom ?? 0;

    const root = document.createElement("div");
    root.style.position = "fixed";
    root.style.inset = "0";
    root.style.zIndex = String(zIndex);
    root.style.display = "none";
    root.style.alignItems = "center";
    root.style.justifyContent = "center";
    root.style.background = "rgba(0,0,0,0.55)";
    root.style.backdropFilter = "blur(6px)";
    root.style.color = "#fff";
    root.style.fontFamily = "system-ui, -apple-system, Segoe UI, Roboto, Arial";

    const box = document.createElement("div");
    box.style.width = "min(520px, calc(100% - 32px))";
    box.style.borderRadius = "18px";
    box.style.background = "rgba(10, 16, 30, 0.95)";
    box.style.border = "1px solid rgba(255,255,255,0.12)";
    box.style.padding = "18px";
    box.style.boxShadow = "0 20px 60px rgba(0,0,0,0.35)";
    box.style.transform = `translateY(${-safeBottom / 2}px)`;

    const title = document.createElement("div");
    title.textContent = "Kết quả";
    title.style.fontSize = "18px";
    title.style.fontWeight = "800";
    title.style.marginBottom = "12px";

    const scoreEl = document.createElement("div");
    scoreEl.style.fontSize = "16px";
    scoreEl.style.fontWeight = "700";

    const timeEl = document.createElement("div");
    timeEl.style.marginTop = "6px";
    timeEl.style.opacity = "0.9";

    const btnRow = document.createElement("div");
    btnRow.style.display = "flex";
    btnRow.style.gap = "10px";
    btnRow.style.marginTop = "16px";

    const mkBtn = (label: string) => {
      const b = document.createElement("button");
      b.textContent = label;
      b.style.flex = "1";
      b.style.padding = "10px 12px";
      b.style.borderRadius = "12px";
      b.style.border = "0";
      b.style.cursor = "pointer";
      b.style.fontWeight = "700";
      return b;
    };

    const replay = mkBtn("Chơi lại");
    replay.style.background = "#2b5cff";
    replay.style.color = "#fff";
    replay.onclick = () => opts?.onReplay?.();

    const exit = mkBtn("Thoát");
    exit.style.background = "rgba(255,255,255,0.10)";
    exit.style.color = "#fff";
    exit.onclick = () => opts?.onExit?.();

    btnRow.append(replay, exit);
    box.append(title, scoreEl, timeEl, btnRow);
    root.appendChild(box);
    mount.appendChild(root);

    this.root = root;
    // this.box = box;
    this.scoreEl = scoreEl;
    this.timeEl = timeEl;
  }

  show(data: { score: number; elapsedMs: number }) {
    this.scoreEl.textContent = `Score: ${data.score}`;
    this.timeEl.textContent = `Time: ${ScoreTimer.formatMs(data.elapsedMs)}`;
    this.root.style.display = "flex";
  }

  hide() {
    this.root.style.display = "none";
  }

  destroy() {
    this.root.remove();
  }
}
