// src/core/runtime/ui/hudDom.ts
import { ScoreTimer } from "../score/scoreTimer";

export type HudOptions = {
  /** container để gắn HUD (default document.body) */
  mount?: HTMLElement;
  /** safe inset (px) từ ScaleManager hoặc CSS env(safe-area-inset-*) */
  safeTop?: number;
  safeLeft?: number;
  zIndex?: number;
};

export class ScoreTimerHudDom {
  private root: HTMLDivElement;
  private scoreEl: HTMLSpanElement;
  private timeEl: HTMLSpanElement;

  constructor(opts?: HudOptions) {
    const mount = opts?.mount ?? document.body;
    const safeTop = opts?.safeTop ?? 0;
    const safeLeft = opts?.safeLeft ?? 0;
    const zIndex = opts?.zIndex ?? 9999;

    const root = document.createElement("div");
    root.style.position = "fixed";
    root.style.top = `${safeTop + 12}px`;
    root.style.left = `${safeLeft + 12}px`;
    root.style.zIndex = String(zIndex);
    root.style.display = "flex";
    root.style.gap = "10px";
    root.style.alignItems = "center";
    root.style.padding = "10px 12px";
    root.style.borderRadius = "14px";
    root.style.background = "rgba(0,0,0,0.55)";
    root.style.backdropFilter = "blur(6px)";
    root.style.color = "#fff";
    root.style.fontFamily = "system-ui, -apple-system, Segoe UI, Roboto, Arial";
    root.style.fontSize = "14px";
    root.style.userSelect = "none";
    root.style.pointerEvents = "none"; // không chặn game

    const score = document.createElement("span");
    score.textContent = "Score: 0";
    score.style.fontWeight = "700";

    const time = document.createElement("span");
    time.textContent = "Time: 00:00";
    time.style.opacity = "0.9";

    root.append(score, time);
    mount.appendChild(root);

    this.root = root;
    this.scoreEl = score;
    this.timeEl = time;
  }

  update(snapshot: { score: number; elapsedMs: number }) {
    this.scoreEl.textContent = `Score: ${snapshot.score}`;
    this.timeEl.textContent = `Time: ${ScoreTimer.formatMs(snapshot.elapsedMs)}`;
  }

  setVisible(v: boolean) {
    this.root.style.display = v ? "flex" : "none";
  }

  destroy() {
    this.root.remove();
  }
}
