// src/core/game/statsCore.ts
/* eslint-disable @typescript-eslint/no-explicit-any */

import { spyPush } from "../shared/sdkSpy";

function clamp01(n: number) {
  if (!Number.isFinite(n)) return 0;
  return Math.max(0, Math.min(1, n));
}

export type AttemptProgress = {
  attemptIndex: number; // 1-based
  correct: number;
  wrong: number; // mistakes attempt hiện tại
  total: number;
  completion: number; // 0..1
  accuracy: number; // 0..1
  finalScore: number;
  startedAtMs: number;
  endedAtMs?: number;
  outcome?: "pass" | "fail" | "quit";
  /** thời gian hoàn thành từng câu (ms), theo thứ tự câu trong attempt */
  questionDurationsMs: number[];
};

type PassCriteria = {
  accuracyThreshold: number; // 0..1
  requireCompletion?: boolean; // default true
};

type StatsState = {
  // session-level counters (KHÔNG reset khi retry)
  hintCount: number;
  retryCount: number;
  sessionMistakeCount: number; // mistakes toàn session

  // total target để tính completion
  total: number;

  // score metrics
  finalScore: number; // attempt hiện tại
  bestScore: number; // best trong session

  // attempt-level counters (reset khi retry)
  attemptCorrect: number;
  attemptWrong: number; //  mistakes attempt hiện tại

  // attempt history
  attempts: AttemptProgress[];

  // current attempt meta
  attemptStartedAtMs: number;

  questionDurationsMs: number[];       // durations của từng câu (ms)
  currentQuestionStartedAtMs?: number; // start time của câu hiện tại
};

let passCriteria: PassCriteria = {
  accuracyThreshold: 0.6, // default (ví dụ)
  requireCompletion: true,
};

const state: StatsState = {
  hintCount: 0,
  retryCount: 0,
  sessionMistakeCount: 0,

  total: 0,

  finalScore: 0,
  bestScore: 0,

  attemptCorrect: 0,
  attemptWrong: 0,

  attempts: [],
  attemptStartedAtMs: performance.now(),

  questionDurationsMs: [],
  currentQuestionStartedAtMs: undefined,
};

// ===== internal helpers =====
function getAttemptIndex() {
  return state.attempts.length + 1; // attempt đang chạy
}

function computeAccuracy() {
  const c = state.attemptCorrect;
  const w = state.attemptWrong;
  const denom = c + w;
  return denom <= 0 ? 0 : c / denom;
}

function computeCompletion() {
  if (state.total <= 0) return 0;
  // completion = đúng / tổng (theo đúng yêu cầu bạn)
  return clamp01(state.attemptCorrect / state.total);
}

function snapshotAttemptPartial(): AttemptProgress {
  return {
    attemptIndex: getAttemptIndex(),
    correct: state.attemptCorrect,
    wrong: state.attemptWrong,
    total: state.total,
    completion: computeCompletion(),
    accuracy: computeAccuracy(),
    finalScore: state.finalScore,
    startedAtMs: state.attemptStartedAtMs,
    outcome: state.attempts[state.attempts.length - 1]?.outcome,
    questionDurationsMs: [...state.questionDurationsMs],
  };
}

// ===== public API =====

function nowMs() {
  return performance.now();
}

/**
 * Gọi khi UI/game bắt đầu hiển thị 1 câu hỏi mới.
 * Nếu còn câu trước chưa finish thì tự đóng để tránh “rò timer”.
 */
export function startQuestionTimer() {
  if (typeof state.currentQuestionStartedAtMs === "number") {
    finishQuestionTimer(); // auto-close previous question
  }
  state.currentQuestionStartedAtMs = nowMs();
  
  // ✅ spy
  spyPush("stats", "startQuestionTimer", { ok: true });
}

/**
 * Gọi khi user trả lời xong 1 câu (dù đúng hay sai tuỳ bạn muốn tính).
 * Returns duration (ms) hoặc null nếu chưa start.
 */
export function finishQuestionTimer() {
  const start = state.currentQuestionStartedAtMs;

  // ✅ log cả trường hợp “chưa start” để test/spy biết game đang dùng timer nhưng gọi sai nhịp
  if (typeof start !== "number") {
    spyPush("stats", "finishQuestionTimer", { ok: false, reason: "not_started" });
    return null;
  }

  const d = Math.max(0, nowMs() - start);
  state.questionDurationsMs.push(d);

  state.currentQuestionStartedAtMs = undefined;

  // ✅ spy
  spyPush("stats", "finishQuestionTimer", {
    ok: true,
    durationMs: d,
    count: state.questionDurationsMs.length,
  });

  return d;
}

/** Optional: nếu bạn đã có duration sẵn từ nơi khác */
export function recordQuestionDuration(durationMs: number) {
  const d = Number.isFinite(durationMs) ? Math.max(0, durationMs) : 0;
  state.questionDurationsMs.push(d);
}

export function setTotal(total: number) {
  state.total = Math.max(0, Math.floor(total));
  spyPush("stats", "setTotal", { total: state.total });
}

export function addHint() {
  state.hintCount += 1;
  spyPush("stats", "addHint", { hintCount: state.hintCount });
}

/** sai 1 lần: tăng cả attemptWrong và sessionMistakeCount */
export function recordWrong() {
  state.attemptWrong += 1;
  state.sessionMistakeCount += 1;
  spyPush("stats", "recordWrong", {
    attemptWrong: state.attemptWrong,
    sessionMistakeCount: state.sessionMistakeCount
  });
}

/**
 * đúng 1 lần:
 * - tăng attemptCorrect
 * - cập nhật score (delta hoặc abs)
 * - cập nhật bestScore
 */
export function recordCorrect(opts?: { scoreDelta?: number; scoreAbs?: number }) {
  state.attemptCorrect += 1;

  if (typeof opts?.scoreAbs === "number" && Number.isFinite(opts.scoreAbs)) {
    state.finalScore = opts.scoreAbs;
  } else if (typeof opts?.scoreDelta === "number" && Number.isFinite(opts.scoreDelta)) {
    state.finalScore += opts.scoreDelta;
  }

  if (state.finalScore > state.bestScore) {
    state.bestScore = state.finalScore;
  }

  spyPush("stats", "recordCorrect", {
    attemptCorrect: state.attemptCorrect,
    finalScore: state.finalScore,
    bestScore: state.bestScore,
    opts
  });
}

/**
 * retryFromStart:
 * - KHÔNG auto finalize attempt
 * - tăng retryCount
 * - reset attempt-level counters + finalScore
 */
export function retryFromStart() {
  state.retryCount += 1;

  state.attemptCorrect = 0;
  state.attemptWrong = 0;
  state.finalScore = 0;
  state.attemptStartedAtMs = performance.now();

  state.questionDurationsMs = [];
  state.currentQuestionStartedAtMs = undefined;

  spyPush("stats", "retryFromStart", { retryCount: state.retryCount });
}

export function setPassCriteria(c: Partial<PassCriteria>) {
  if (typeof c.accuracyThreshold === "number") {
    // clamp 0..1
    const v = Math.max(0, Math.min(1, c.accuracyThreshold));
    passCriteria.accuracyThreshold = v;
  }
  if (typeof c.requireCompletion === "boolean") {
    passCriteria.requireCompletion = c.requireCompletion;
  }
}

function decidePassFail(): "pass" | "fail" {
  const a = snapshotAttemptPartial(); // có accuracy/completion
  const doneOk = passCriteria.requireCompletion ? a.completion >= 1 : true;
  const accOk = a.accuracy >= passCriteria.accuracyThreshold;

  return doneOk && accOk ? "pass" : "fail";
}

/**
 * finalize khi game chuyển sang endgame hoặc quit game
 * - nếu outcome === "quit" => lưu quit
 * - nếu outcome không truyền => tự tính pass/fail theo rule chung
 */
export function finalizeAttempt(outcome?: "quit" | "pass" | "fail") {
  if (typeof state.currentQuestionStartedAtMs === "number") {
    finishQuestionTimer();
  }

  const a = snapshotAttemptPartial();
  a.endedAtMs = performance.now();

  if (outcome === "quit") {
    a.outcome = "quit";
  } else if (outcome === "pass" || outcome === "fail") {
    a.outcome = outcome;
  } else {
    // tự tính
    a.outcome = decidePassFail();
  }

  state.attempts.push(a);

  spyPush("stats", "finalizeAttempt", { outcome: state.attempts[state.attempts.length - 1]?.outcome });
}

/** getters cho submit */
export function getStatsSnapshot() {
  return {
    // session counters
    hintCount: state.hintCount,
    retryCount: state.retryCount,
    sessionMistakeCount: state.sessionMistakeCount,

    // attempt metrics hiện tại
    finalScore: state.finalScore,
    bestScore: state.bestScore,
    accuracy: computeAccuracy(),
    completion: computeCompletion(),

    // chi tiết mistakes attempt
    attemptMistakeCount: state.attemptWrong,

    // history json theo attempt
    attempts: [...state.attempts],

    // debug / optional
    currentAttempt: snapshotAttemptPartial(),
  };
}

export function resetAll() {
  state.hintCount = 0;
  state.retryCount = 0;
  state.sessionMistakeCount = 0;

  state.total = 0;

  state.finalScore = 0;
  state.bestScore = 0;

  state.attemptCorrect = 0;
  state.attemptWrong = 0;

  state.attempts = [];
  state.attemptStartedAtMs = performance.now();
  
  spyPush("stats", "resetAll");
}

// Hàm tổng hợp dữ liệu khi game hoàn thành
export function prepareSubmitData() {
  const snap = getStatsSnapshot();

  // Tạo payload tổng hợp gửi lên Hub
  const payload = {
    finalScore: snap.finalScore,        // Điểm số cuối cùng
    accuracy: snap.accuracy,          // Độ chính xác hiện tại (lần cuối lần thử)
    bestScore: snap.bestScore,         // Điểm cao nhất
    completion: snap.completion,        // Tiến độ hoàn thành hiện tại
    completion_history: snap.attempts, // Lịch sử tiến độ theo từng lần thử
    hintCount: snap.hintCount,         // Số lần sử dụng gợi ý
    mistakeCount: snap.sessionMistakeCount,      // Số lần mắc lỗi
    retryCount: snap.retryCount,        // Số lần thử lại
    outcome: snap.currentAttempt?.outcome,
  };

  // ✅ thêm spy
  spyPush("stats", "prepareSubmitData", {
    // đừng push cả completion_history nếu sợ vượt size
    finalScore: payload.finalScore,
    accuracy: payload.accuracy,
    bestScore: payload.bestScore,
    completion: payload.completion,
    hintCount: payload.hintCount,
    mistakeCount: payload.mistakeCount,
    retryCount: payload.retryCount,
    outcome: payload.outcome,
    attemptsCount: snap.attempts.length
  });

  return payload;
}