// src/core/runtime/score/scoreTimer.ts
export type ScoreTimerState = {
  running: boolean;
  startAtMs: number | null;
  elapsedMs: number;
  score: number;
};

export class ScoreTimer {
  private state: ScoreTimerState = {
    running: false,
    startAtMs: null,
    elapsedMs: 0,
    score: 0,
  };

  start(nowMs = performance.now()) {
    if (this.state.running) return;
    this.state.running = true;
    this.state.startAtMs = nowMs;
  }

  pause(nowMs = performance.now()) {
    if (!this.state.running) return;
    this.state.elapsedMs = this.getElapsedMs(nowMs);
    this.state.running = false;
    this.state.startAtMs = null;
  }

  reset() {
    this.state.running = false;
    this.state.startAtMs = null;
    this.state.elapsedMs = 0;
    this.state.score = 0;
  }

  setScore(score: number) {
    this.state.score = Math.max(0, Math.floor(score));
  }

  addScore(delta: number) {
    this.setScore(this.state.score + delta);
  }

  getScore() {
    return this.state.score;
  }

  getElapsedMs(nowMs = performance.now()) {
    if (!this.state.running || this.state.startAtMs == null) return this.state.elapsedMs;
    return this.state.elapsedMs + (nowMs - this.state.startAtMs);
  }

  snapshot(nowMs = performance.now()) {
    return {
      score: this.getScore(),
      elapsedMs: Math.max(0, Math.floor(this.getElapsedMs(nowMs))),
      running: this.state.running,
    };
  }

  static formatMs(ms: number) {
    const totalSec = Math.max(0, Math.floor(ms / 1000));
    const m = Math.floor(totalSec / 60);
    const s = totalSec % 60;
    const mm = String(m).padStart(2, "0");
    const ss = String(s).padStart(2, "0");
    return `${mm}:${ss}`;
  }
}
