import {
  connectToHub,
  type LaunchContext,
  type GameBridge,
  ErrorCode,
} from "@iruka-edu/game-core";
import { OverlayManager } from "../../runtime/ui/OverlayManager";
import { IrukaPlugin, IRUKA_PLUGIN_KEY } from "../../phaser/IrukaPlugin";

export abstract class BaseGame {
  protected bridge!: GameBridge;
  protected context!: LaunchContext;
  protected ui: OverlayManager;

  constructor() {
    this.ui = new OverlayManager();
    this.ui.showLoading(); // Show loading immediately

    // Auto-bootstrap when new Game() is called
    this.bootstrap().catch((err) => {
      console.error("☠️ Game Bootstrap Failed:", err);
      // Show fatal error screen
      this.ui.showError(err.message, err.code);
    });
  }

  private async bootstrap() {
    console.log("🚀 Starting Game Bootstrap...");

    try {
      // 1. Auto Handshake (Uses Core with Validation)
      this.bridge = await connectToHub();

      // Update context from bridge
      // Note: connectToHub returns GameBridge which has 'context' property
      this.context = this.bridge.context;

      console.log("✅ Connected to Hub. Mode:", this.context.mode);

      // 2. Call Lifecycle Hooks of Child Game
      await this.onInit(this.context);

      // 3. Initialize Phaser plugin if Phaser game exists
      this.initializePhaserPlugin();

      // Hide loading before starting (or let onStart handle it? User guide says hide after bootstrap)
      this.ui.hide();

      await this.onStart();
    } catch (error: any) {
      if (error?.code === ErrorCode.SYS_INVALID_CONTEXT) {
        // Handle Validation specific error
        console.error("Hub sent bad data!");
      }
      throw error;
    }
  }

  /**
   * Initialize Phaser plugin if a Phaser game instance is available
   * This allows scenes to access SDK via this.iruka
   */
  private initializePhaserPlugin() {
    // Check if there's a global Phaser game instance
    if (typeof window !== 'undefined' && (window as any).phaserGame) {
      const game = (window as any).phaserGame;
      
      // Wait for game to be ready before initializing plugin
      if (game.isBooted) {
        this.injectPluginToPhaserGame(game);
      } else {
        game.events.once('ready', () => {
          this.injectPluginToPhaserGame(game);
        });
      }
    }
  }

  /**
   * Inject the bridge into the Phaser plugin
   */
  private injectPluginToPhaserGame(game: any) {
    const plugin = game.plugins.get(IRUKA_PLUGIN_KEY) as IrukaPlugin;
    
    if (plugin) {
      // Initialize plugin with the bridge instance
      plugin.init(this.bridge);
      console.log("✅ Phaser IrukaPlugin initialized with bridge");
    } else {
      console.warn("⚠️ IrukaPlugin not found in Phaser game. Make sure to include it in your game config.");
    }
  }

  /**
   * Helper to merge default SDK plugins with Developer's config.
   * Game Devs should call this if they override getGameConfig.
   */
  protected getStandardPhaserConfig(overrides: Phaser.Types.Core.GameConfig): Phaser.Types.Core.GameConfig {
    const plugins = overrides.plugins || {};
    const globalPlugins = Array.isArray(plugins) ? plugins : (plugins.global || []);
    
    return {
      ...overrides,
      plugins: {
        ...plugins,
        global: [
          ...globalPlugins,
          {
            key: IRUKA_PLUGIN_KEY,
            plugin: IrukaPlugin,
            start: true,
            mapping: 'iruka' // <--- MAGIC: Defines "this.iruka" in Scenes
          }
        ]
      }
    };
  }

  // --- Abstract Methods for Child Games ---
  protected abstract onInit(context: LaunchContext): Promise<void>;
  protected abstract onStart(): Promise<void>;
}
