// -------------------- Envelope --------------------

export interface MsgEnvelope<T = unknown> {
  sdkVersion: string;
  sessionId: string;
  gameId: string;
  lessonId?: string;
  gameVersion?: string;
  source: "hub" | "game";
  type: string;
  payload?: T;
}

// -------------------- Message Types --------------------
export const MessageType = {
  // System handshake
  HELLO: "SYS:HELLO", // Game -> Hub: "I'm online"
  INIT: "CMD:INIT", // Hub -> Game: "Here's your context"

  // Game lifecycle commands (Hub -> Game)
  START: "CMD:START",
  PAUSE: "CMD:PAUSE",
  RESUME: "CMD:RESUME",
  RESIZE: "CMD:RESIZE",
  QUIT: "CMD:QUIT",
  SET_STATE: "CMD:SET_STATE",

  // Game events (Game -> Hub)
  READY: "EVT:READY",
  LOADING: "EVT:LOADING",
  SCORE_UPDATE: "EVT:SCORE_UPDATE",
  PROGRESS: "EVT:PROGRESS",
  COMPLETE: "EVT:COMPLETE",
  ERROR: "EVT:ERROR",
  REQUEST_SAVE: "EVT:REQUEST_SAVE",
  REQUEST_LOAD: "EVT:REQUEST_LOAD",
} as const;

// -------------------- Commands: Hub -> Game --------------------

export type HubCommand =
  | { type: "INIT"; payload: LaunchContext }
  | { type: "START" }
  | { type: "PAUSE" }
  | { type: "RESUME" }
  | { type: "RESIZE"; payload: { width: number; height: number; dpr: number } }
  | { type: "QUIT" }
  | { type: "SET_STATE"; payload: any };

import { LaunchContext } from "../contract/types";

// -------------------- Events: Game -> Hub --------------------

export type GameErrorCode =
  | "INIT_FAILED"
  | "ASSET_LOAD_FAILED"
  | "RUNTIME_ERROR"
  | "TIMEOUT"
  | "UNKNOWN";

export type GameEvent =
  | { type: "READY"; payload?: { capabilities?: string[] } }
  | { type: "LOADING"; payload: { progress: number } }
  | { type: "SCORE_UPDATE"; payload: { score: number; delta?: number } }
  | { type: "PROGRESS"; payload: any }
  | {
      type: "COMPLETE";
      payload: { score: number; timeMs: number; extras?: any };
    }
  | {
      type: "ERROR";
      payload: { code: GameErrorCode; message: string; detail?: any };
    }
  | { type: "REQUEST_SAVE"; payload: any }
  | { type: "REQUEST_LOAD"; payload?: undefined };

// -------------------- Helpers --------------------

export function makeEnvelope<TPayload = unknown>(params: {
  sdkVersion: string;
  source: "hub" | "game";
  sessionId: string;
  gameId: string;
  lessonId?: string;
  gameVersion?: string;
  type: string;
  payload?: TPayload;
}): MsgEnvelope<TPayload> {
  return {
    sdkVersion: params.sdkVersion,
    sessionId: params.sessionId,
    gameId: params.gameId,
    lessonId: params.lessonId,
    gameVersion: params.gameVersion,
    source: params.source,
    type: params.type,
    payload: params.payload,
  };
}

export function isRecord(v: unknown): v is Record<string, unknown> {
  return typeof v === "object" && v !== null && !Array.isArray(v);
}

export function isValidEnvelope(v: unknown): v is MsgEnvelope<any> {
  if (!isRecord(v)) return false;
  if (typeof v.sdkVersion !== "string") return false;
  if (typeof v.sessionId !== "string") return false;
  if (typeof v.gameId !== "string") return false;
  if (v.source !== "hub" && v.source !== "game") return false;
  if (typeof v.type !== "string") return false;
  return true;
}

const HUB_COMMAND_TYPES = [
  "INIT",
  "START",
  "PAUSE",
  "RESUME",
  "RESIZE",
  "QUIT",
  "SET_STATE",
] as const;
const GAME_EVENT_TYPES = [
  "READY",
  "LOADING",
  "SCORE_UPDATE",
  "PROGRESS",
  "COMPLETE",
  "ERROR",
  "REQUEST_SAVE",
  "REQUEST_LOAD",
] as const;

export function isHubCommandType(t: string): t is HubCommand["type"] {
  return HUB_COMMAND_TYPES.includes(t as any);
}

export function isGameEventType(t: string): t is GameEvent["type"] {
  return GAME_EVENT_TYPES.includes(t as any);
}

export function clamp01(n: number): number {
  if (!Number.isFinite(n)) return 0;
  return Math.min(1, Math.max(0, n));
}

export const MAX_MESSAGE_BYTES = 16 * 1024; // 16KB

export function estimateJsonBytes(value: unknown): number {
  try {
    return new TextEncoder().encode(JSON.stringify(value)).length;
  } catch {
    return 0;
  }
}

export function validateMessageSize(envelope: unknown): {
  ok: boolean;
  error?: string;
} {
  const size = estimateJsonBytes(envelope);
  if (size > MAX_MESSAGE_BYTES) {
    return {
      ok: false,
      error: `Message too large: ${size} bytes (max ${MAX_MESSAGE_BYTES})`,
    };
  }
  return { ok: true };
}
