/* eslint-disable @typescript-eslint/no-explicit-any */

import {
  type MsgEnvelope,
  // type HubCommand,
  type GameEvent,
  type LaunchContext,
  type GameErrorCode,
  makeEnvelope,
  validateIncomingEnvelope,
  parseHubCommandFromEnvelope,
  clamp01,
  estimateJsonBytes,
  MAX_MESSAGE_BYTES,
} from "../protocol/protocol";
import { setSdkContext } from "../shared/sdkContext";
import { spyPush } from "../shared/sdkSpy";

export type GameSdkOptions = {
  /** Hub origin hợp lệ. Nên truyền từ query param hoặc hardcode env của hub */
  hubOrigin: string;

  /** Optional: allowlist origin (mặc định chỉ cho hubOrigin) */
  allowlistHubOrigins?: string[];

  /** Hooks */
  onInit?: (ctx: LaunchContext) => void;
  onStart?: () => void;
  onPause?: () => void;
  onResume?: () => void;
  onResize?: (size: { width: number; height: number; dpr: number }) => void;
  onQuit?: () => void;

  /** log */
  onInvalidMessage?: (info: { reason: string; origin: string; data: unknown }) => void;
  onSetState?: (state: any) => void;
};

export type GameSdk = {
  /** gọi khi game sẵn sàng */
  ready: (payload?: { capabilities?: string[] }) => void;

  /** báo tiến độ loading 0..1 (auto throttle <=10/s) */
  loading: (progress01: number) => void;

  /** update điểm (auto gộp 100ms) */
  score: (score: number, delta?: number) => void;

  /** snapshot tiến độ nhỏ (nhớ <=16KB) */
  progress: (payload: any) => void;

  /** kết thúc phiên */
  complete: (payload: { score?: number; timeMs: number; extras?: any }) => void;

  /** báo lỗi */
  error: (payload: { code: GameErrorCode; message: string; detail?: any }) => void;

  /** destroy listeners */
  destroy: () => void;

  /** thông tin session hiện tại (có sau INIT) */
  getSessionId: () => string | null;

  requestSave: (payload: any) => void;
  requestLoad: () => void;
};

function normalizeOrigin(origin: string): string {
  return origin.replace(/\/+$/, "");
}

// Detect DEV mode - compatible with both ESM and CJS
// Check if running on localhost or if explicitly set via window.__DEV__
const DEV = 
  (typeof window !== "undefined" && (window as any).__DEV__) ||
  (typeof location !== "undefined" && (location.hostname === "localhost" || location.hostname === "127.0.0.1"));

function inferHubOrigin(fallback: string): string {
  // Khi game chạy trong iframe, document.referrer = URL của Hub
  try {
    if (typeof document !== "undefined" && document.referrer) {
      return new URL(document.referrer).origin;
    }
  } catch {
    // ignore
  }
  return fallback;
}

function safePostToParent(env: MsgEnvelope<any>, targetOrigin: string) {
  // DEV: cho dễ test, PROD: bắt buộc đúng origin của Hub
  window.parent.postMessage(env, DEV ? "*" : targetOrigin);
}

export function createGameSdk(opts: GameSdkOptions): GameSdk {
  // ưu tiên suy ra từ referrer để khỏi hardcode sai port/domain
  const hubOrigin = normalizeOrigin(inferHubOrigin(opts.hubOrigin));

  // DEV: nới allowlist để khỏi drop message vì origin khác nhau
  // (HMR, proxy, khác port...)
  const allow = DEV
    ? null
    : new Set((opts.allowlistHubOrigins ?? [hubOrigin]).map(normalizeOrigin));

  let destroyed = false;
  let sessionId: string | null = null;
  let sdkVersion: string;
  let gameId: string;
  let lessonId: string | undefined;
  let gameVersion: string | undefined;

  // throttle LOADING: max 10/s
  let loadingWindowStart = 0;
  let loadingCount = 0;

  // SCORE_UPDATE gộp 100ms
  let scoreFlushTimer: number | null = null;
  let pendingScore: { score: number; delta?: number } | null = null;

  function invalid(reason: string, origin: string, data: unknown) {
    opts.onInvalidMessage?.({ reason, origin, data });
  }

  function sendEvent<TPayload>(type: GameEvent["type"], payload?: TPayload) {
    if (destroyed) return;
    if (!sessionId) {
      // chưa INIT thì chưa có sessionId -> không gửi bừa
      return;
    }

    const env = makeEnvelope({
      sdkVersion,
      source: "game",
      sessionId,
      gameId,
      lessonId,
      gameVersion,
      type,
      payload,
    });

    const bytes = estimateJsonBytes(env);
    spyPush("sdk", "sendEvent", { type, bytes });
    if (bytes > MAX_MESSAGE_BYTES) {
      spyPush("sdk", "payloadTooLarge", { type, bytes, limit: MAX_MESSAGE_BYTES });
        // Không gửi quá cỡ; báo lỗi nội bộ tối thiểu
        // (tránh loop: gửi ERROR cũng có thể quá cỡ nếu detail quá lớn)
      const tiny = makeEnvelope({
        sdkVersion,
        source: "game",
        sessionId,
        gameId,
        lessonId,
        gameVersion,
        type: "ERROR",
        payload: {
          code: "RUNTIME_EXCEPTION",
          message: `payload_too_large: ${bytes} bytes`,
        } as any,
      });
      safePostToParent(tiny, hubOrigin);
      return;
    }

    safePostToParent(env, hubOrigin);
  }

  // ===== ErrorReporter (production) =====

  // giới hạn gửi lỗi để tránh spam hub
  const ERROR_MAX_PER_SESSION = 10;
  const ERROR_MIN_INTERVAL_MS = 400;     // throttle
  const ERROR_DEDUPE_WINDOW_MS = 5000;   // dedupe cùng lỗi trong 5s
  const ERROR_BUFFER_MAX = 5;            // lưu lỗi trước INIT

  let errorSentCount = 0;
  let lastErrorSentAt = 0;

  // dedupe cache: key -> lastTime
  const recentErrorKeys = new Map<string, number>();

  // buffer lỗi trước INIT (chưa có sessionId)
  const bufferedErrors: Array<{ code: any; message: string; detail?: any }> = [];

  function normalizeErrorMessage(msg: unknown): string {
    const s = typeof msg === "string" ? msg : msg ? String(msg) : "Unknown error";
    // cắt bớt để không quá dài
    return s.length > 500 ? s.slice(0, 500) + "…" : s;
  }

  function safeSerializeDetail(detail: any, maxLen = 2000) {
    // cố gắng stringify an toàn, cắt độ dài
    try {
      const json = JSON.stringify(detail, (_k, v) => {
        // tránh circular/too deep objects
        if (v instanceof Error) {
          return { name: v.name, message: v.message, stack: v.stack };
        }
        return v;
      });
      if (json.length <= maxLen) return JSON.parse(json);
      return { truncated: true, preview: json.slice(0, maxLen) + "…" };
    } catch {
      // fallback tối thiểu
      return { unserializable: true, preview: normalizeErrorMessage(detail) };
    }
  }

  function makeErrorKey(code: any, message: string, detail?: any) {
    // key dedupe: code + message + (filename/lineno nếu có)
    const d = detail ?? {};
    const loc = `${d?.filename ?? ""}:${d?.lineno ?? ""}:${d?.colno ?? ""}`;
    return `${String(code)}|${message}|${loc}`;
  }

  function canSendErrorNow(key: string) {
    const now = performance.now();

    // limit số lỗi / session
    if (errorSentCount >= ERROR_MAX_PER_SESSION) return false;

    // throttle
    if (now - lastErrorSentAt < ERROR_MIN_INTERVAL_MS) return false;

    // dedupe
    const last = recentErrorKeys.get(key);
    if (last && now - last < ERROR_DEDUPE_WINDOW_MS) return false;

    return true;
  }

  function markErrorSent(key: string) {
    const now = performance.now();
    lastErrorSentAt = now;
    errorSentCount += 1;
    recentErrorKeys.set(key, now);

    // dọn map cho khỏi phình
    if (recentErrorKeys.size > 50) {
      for (const [k, t] of recentErrorKeys) {
        if (now - t > ERROR_DEDUPE_WINDOW_MS) recentErrorKeys.delete(k);
      }
    }
  }

  function reportError(code: any, message: string, detail?: any) {
    try {
      const msg = normalizeErrorMessage(message);
      const safeDetail = detail ? safeSerializeDetail(detail) : undefined;
      const key = makeErrorKey(code, msg, safeDetail);

      // chưa INIT -> buffer
      if (!sessionId) {
        if (bufferedErrors.length < ERROR_BUFFER_MAX) {
          bufferedErrors.push({ code, message: msg, detail: safeDetail });
        }
        return;
      }

      if (!canSendErrorNow(key)) return;
      markErrorSent(key);

      sendEvent("ERROR", {
        code,
        message: msg,
        detail: safeDetail,
      } as any);
    } catch {
      // tuyệt đối không throw từ ErrorReporter
    }
  }

  function flushBufferedErrorsAfterInit() {
    if (!sessionId) return;
    if (bufferedErrors.length === 0) return;

    // gửi lần lượt nhưng vẫn tôn trọng throttle/limit
    for (const e of bufferedErrors.splice(0)) {
      reportError(e.code, e.message, e.detail);
    }
  }


  function onMessage(event: MessageEvent) {
    if (destroyed) return;

  // 0) Ignore mọi message không phải protocol (quan trọng cho dev/HMR)
  const envRes0 = validateIncomingEnvelope(event.data);
  if (!envRes0.ok) return;

  const origin = normalizeOrigin(event.origin);

  // 1) origin allowlist
  if (!DEV && allow && !allow.has(origin)) {
    invalid("origin_not_allowed", origin, event.data);
    return;
  }

  // 2) must come from parent window
  if (event.source !== window.parent) {
    invalid("source_not_parent", origin, event.data);
    return;
  }

  const env = envRes0.value;

  // 3) parse as HubCommand
  const cmdRes = parseHubCommandFromEnvelope(env);
  if (!cmdRes.ok) {
    invalid(`invalid_hub_command: ${cmdRes.error}`, origin, event.data);
    return;
  }

    const cmd = cmdRes.value;
    spyPush("hub", "recvCommand", { type: cmd.type });

    // INIT sets sessionId (must match payload.sessionId)
    if (cmd.type === "INIT") {
      // lấy từ envelope (ưu tiên) để chắc chắn đồng bộ với Hub
      sdkVersion = env.sdkVersion;
      sessionId = env.sessionId;
      gameId = env.gameId;
      lessonId = env.lessonId;
      gameVersion = env.gameVersion;
      spyPush("hub", "init", { sessionId });

      setSdkContext({
        sdkVersion,
        sessionId,
        gameId,
        lessonId,
        gameVersion,
        hubOrigin,
      });

      // (optional) sanity check payload vs envelope
      if (cmd.payload?.sessionId && cmd.payload.sessionId !== sessionId) {
        invalid("sessionId_mismatch_envelope_vs_payload", origin, event.data);
        return;
      }
      if ((cmd.payload as any)?.gameId && (cmd.payload as any).gameId !== gameId) {
        invalid("gameId_mismatch_envelope_vs_payload", origin, event.data);
        return;
      }
      if ((cmd.payload as any)?.lessonId && (cmd.payload as any).lessonId !== lessonId) {
        invalid("lessonId_mismatch_envelope_vs_payload", origin, event.data);
        return;
      }

      // reset error stats
      errorSentCount = 0;
      lastErrorSentAt = 0;
      recentErrorKeys.clear();

      opts.onInit?.(cmd.payload);
      flushBufferedErrorsAfterInit();
      return;
    }

    // mọi lệnh khác yêu cầu đã INIT
    if (!sessionId) {
      invalid("command_before_init", origin, event.data);
      return;
    }

    // session mismatch guard
    if (env.sessionId !== sessionId) {
      invalid("sessionId_mismatch", origin, event.data);
      return;
    }

    switch (cmd.type) {
      case "START":
        opts.onStart?.();
        break;
      case "PAUSE":
        opts.onPause?.();
        break;
      case "RESUME":
        opts.onResume?.();
        break;
      case "RESIZE":
        opts.onResize?.(cmd.payload);
        break;
      case "QUIT":
        opts.onQuit?.();
        break;
      case "SET_STATE":
        // optional hook để game nhận state từ hub
        (opts as any).onSetState?.(cmd.payload);
        break;
    }
  }

  window.addEventListener("message", onMessage);

  // crash guards -> ERROR (production)
  const onUnhandledRejection = (e: PromiseRejectionEvent) => {
    reportError(
      "UNHANDLED_REJECTION",
      "Unhandled promise rejection",
      { reason: e.reason }
    );
  };

  const onWindowError = (e: ErrorEvent) => {
    // phân biệt resource error (script/img/css load fail) vs runtime error
    const isResourceError = (e as any)?.target && !(e as any)?.error;

    if (isResourceError) {
      const target = (e as any).target as HTMLElement | null;
      reportError(
        "RESOURCE_LOAD_ERROR",
        "Resource load error",
        {
          tagName: target?.tagName,
          src: (target as any)?.src,
          href: (target as any)?.href,
        }
      );
      return;
    }

    reportError(
      "RUNTIME_EXCEPTION",
      e.message || "Window error",
      {
        filename: e.filename,
        lineno: e.lineno,
        colno: e.colno,
        stack: (e.error && (e.error as any).stack) ? String((e.error as any).stack) : undefined,
      }
    );
  };

  window.addEventListener("unhandledrejection", onUnhandledRejection);
  window.addEventListener("error", onWindowError, true); // capture true để bắt resource error tốt hơn

  // Public API
  const api: GameSdk = {
    ready(payload) {
      sendEvent("READY", payload as any);
    },

    loading(progress01) {
      const now = performance.now();
      if (now - loadingWindowStart >= 1000) {
        loadingWindowStart = now;
        loadingCount = 0;
      }
      if (loadingCount >= 10) return; // max 10/s
      loadingCount += 1;
      sendEvent("LOADING", { progress: clamp01(progress01) } as any);
    },

    score(score, delta) {
      pendingScore = { score, delta };

      if (scoreFlushTimer) return;
      scoreFlushTimer = window.setTimeout(() => {
        scoreFlushTimer = null;
        if (!pendingScore) return;
        const last = pendingScore;
        pendingScore = null;
        sendEvent("SCORE_UPDATE", last as any);
      }, 100);
    },

    progress(payload) {
      sendEvent("PROGRESS", payload as any);
    },

    complete(payload) {
      sendEvent("COMPLETE", payload as any);
    },

    error(payload) {
      sendEvent("ERROR", payload as any);
    },

    destroy() {
      if (destroyed) return;
      destroyed = true;

      if (scoreFlushTimer) window.clearTimeout(scoreFlushTimer);
      scoreFlushTimer = null;
      pendingScore = null;

      window.removeEventListener("message", onMessage);
      window.removeEventListener("unhandledrejection", onUnhandledRejection);
      window.removeEventListener("error", onWindowError);
    },

    getSessionId() {
      return sessionId;
    },

    requestSave(payload) {
      sendEvent("REQUEST_SAVE", payload as any);
    },

    requestLoad() {
      sendEvent("REQUEST_LOAD");
    },

  };

  return api;
}
