// createEndGameScene.ts
import Phaser from "phaser";
import { prepareSubmitData, retryFromStart } from "../game";

export type EndGameCompletePayload = {
  score: number;
  timeMs: number;
  extras?: any;
};

export type EndGameData = {
  score: number;
  total?: number;
  startTime?: number; // ms epoch
  extras?: any;
};

export type EndGameAudioAdapter = {
  play: (key: string) => void;
  stopAll?: () => void;
};

export type EndGameOptions = {
  sceneKey?: string; // default: "EndGameScene"

  // Assets: nếu game preload sẵn thì chỉ cần key; nếu chưa có thì cung cấp url để helper preload
  assets: {
    banner: { key: string; url?: string };
    icon?: { key: string; url?: string };
    replayBtn: { key: string; url?: string };
    exitBtn: { key: string; url?: string };
  };

  // Audio optional
  audio?: EndGameAudioAdapter;
  sounds?: {
    enter?: string; // ví dụ "complete"
    fireworks?: string; // ví dụ "fireworks"
    applause?: string; // ví dụ "applause"
    click?: string; // ví dụ "sfx_click"
  };

  dimAlpha?: number; // default 0.5
  designBase?: { w: number; h: number }; // để scale theo thiết kế gốc (default 1280x720)

  confetti?: {
    enabled?: boolean; // default true
    rateMs?: number; // default 100
    colors?: number[]; // default list
  };

  // Replay/Exit behavior
  replaySceneKey?: string; // scene muốn quay về, ví dụ "CompareScene"
  fallbackSceneKey?: string; // nếu exit mà không có reportComplete, chuyển scene này

  onEnter?: () => void; // gọi khi vào EndGame
  onLeave?: () => void; // gọi khi rời EndGame (replay/exit)

  reportComplete?: (payload: EndGameCompletePayload) => void; // hook báo về hub
};

export type EndGameSceneCtor = new (...args: any[]) => Phaser.Scene;

export function createEndGameScene(options: EndGameOptions): EndGameSceneCtor {
  const KEY = options.sceneKey ?? "EndGameScene";
  // const dimAlpha = options.dimAlpha ?? 0.5;
  const base = options.designBase ?? { w: 1280, h: 720 };

  const confettiColors = options.confetti?.colors ?? [
    0xff6b6b, 0x4ecdc4, 0xffe66d, 0x95e1d3, 0xf38181, 0xaa96da,
  ];

  return class SharedEndGameScene extends Phaser.Scene {
    private confettiEvent?: Phaser.Time.TimerEvent;

    private dimBg?: Phaser.GameObjects.Rectangle;
    private banner?: Phaser.GameObjects.Image;
    private icon?: Phaser.GameObjects.Image;
    private replayBtn?: Phaser.GameObjects.Image;
    private exitBtn?: Phaser.GameObjects.Image;

    private dataIn!: EndGameData;

    constructor() {
      super(KEY);
    }

    init(data: EndGameData) {
      this.dataIn = data;
    }

    preload() {
      // chỉ load nếu chưa có texture và có url
      const { assets } = options;

      const loadIfNeeded = (key: string, url?: string) => {
        if (!url) return;
        if (this.textures.exists(key)) return;
        this.load.image(key, url);
      };

      loadIfNeeded(assets.banner.key, assets.banner.url);
      if (assets.icon) loadIfNeeded(assets.icon.key, assets.icon.url);
      loadIfNeeded(assets.replayBtn.key, assets.replayBtn.url);
      loadIfNeeded(assets.exitBtn.key, assets.exitBtn.url);
    }

    create() {
      options.onEnter?.();
      // audio enter
      if (options.audio && options.sounds?.enter)
        options.audio.play(options.sounds.enter);

      // after 2s play fireworks/applause
      this.time.delayedCall(2000, () => {
        if (!options.audio) return;
        if (options.sounds?.fireworks)
          options.audio.play(options.sounds.fireworks);
        if (options.sounds?.applause)
          options.audio.play(options.sounds.applause);
      });

      this.buildUI();
      this.layout();

      // resize reactive
      this.scale.on("resize", () => this.layout());

      // confetti
      if (options.confetti?.enabled !== false) this.startConfetti();
    }

    private buildUI() {
      const w = this.scale.width;
      const h = this.scale.height;

      // dim background bằng Phaser (không phụ thuộc DOM)
      // this.dimBg = this.add.rectangle(0, 0, w, h, 0x000000, dimAlpha).setOrigin(0).setDepth(90);

      // banner
      this.banner = this.add
        .image(w / 2, h / 2 - h * 0.12, options.assets.banner.key)
        .setOrigin(0.5)
        .setDepth(100);

      // icon (optional)
      if (
        options.assets.icon &&
        this.textures.exists(options.assets.icon.key)
      ) {
        this.icon = this.add
          .image(w / 2, h / 2 - 150, options.assets.icon.key)
          .setDepth(110);
        this.icon.setScale(0.5);

        this.tweens.add({
          targets: this.icon,
          y: this.icon.y - 10,
          duration: 800,
          yoyo: true,
          repeat: -1,
          ease: "Sine.easeInOut",
        });

        this.tweens.add({
          targets: this.icon,
          angle: { from: -5, to: 5 },
          duration: 600,
          yoyo: true,
          repeat: -1,
          ease: "Sine.easeInOut",
        });
      }

      // ==== Các nút ngang dưới banner ====
      const btnScale = Math.min(w, h) / 1280;
      const spacing = 250 * btnScale;

      // buttons
      this.replayBtn = this.add
        .image(w / 2 - spacing, h / 2 + h * 0.2, options.assets.replayBtn.key)
        .setOrigin(0.5)
        .setDepth(120)
        .setInteractive({ useHandCursor: true });

      this.exitBtn = this.add
        .image(w / 2 + spacing, h / 2 + h * 0.2, options.assets.exitBtn.key)
        .setOrigin(0.5)
        .setDepth(120)
        .setInteractive({ useHandCursor: true });

      this.replayBtn.on("pointerdown", () => this.onReplay());
      this.exitBtn.on("pointerdown", () => this.onExit());

      // hover (desktop)
      [this.replayBtn, this.exitBtn].forEach((btn) => {
        btn.on("pointerover", () => btn.setScale(btn.scale * 1.1));
        btn.on("pointerout", () => this.layout()); // reset theo layout
      });
    }

    private layout() {
      const w = this.scale.width;
      const h = this.scale.height;

      if (this.dimBg) this.dimBg.setSize(w, h);

      // scale theo base design
      const scale = Math.min(w / base.w, h / base.h);

      // banner full-ish
      if (this.banner) {
        this.banner.setPosition(w / 2, h / 2 - h * 0.12);
        this.banner.setDisplaySize(w * 0.9, h * 0.9);
      }

      // icon
      if (this.icon) {
        this.icon.setPosition(w / 2, h / 2 - 150 * scale);
        this.icon.setScale(0.5 * scale);
      }

      // buttons row
      const btnScale = Math.min(w, h) / 1280;
      const spacing = 250 * btnScale;
      if (this.replayBtn) {
        this.replayBtn.setPosition(w / 2 - spacing, h / 2 + h * 0.2);
        this.replayBtn.setScale(btnScale);
      }
      if (this.exitBtn) {
        this.exitBtn.setPosition(w / 2 + spacing, h / 2 + h * 0.2);
        this.exitBtn.setScale(btnScale);
      }
    }

    private onReplay() {
      if (options.audio && options.sounds?.click)
        options.audio.play(options.sounds.click);
      options.audio?.stopAll?.();
      retryFromStart();

      this.stopConfetti();

      if (options.replaySceneKey) {
        options.onLeave?.();
        this.scene.stop(KEY);
        this.scene.start(options.replaySceneKey);
      } else {
        // default: chỉ restart scene hiện tại
        this.scene.restart();
      }
    }

    private onExit() {
      if (options.audio && options.sounds?.click)
        options.audio.play(options.sounds.click);
      options.audio?.stopAll?.();

      this.stopConfetti();

      const startTime = this.dataIn?.startTime ?? Date.now();
      const timeMs = Math.max(0, Date.now() - startTime);

      // lấy stats tổng hợp từ SDK core
      const stats = prepareSubmitData(); // { finalScore, accuracy, bestScore, completion, ... }

      const payload: EndGameCompletePayload = {
        // score: giữ theo contract hiện tại (Hub đang đọc score)
        score: stats.finalScore ?? this.dataIn?.score ?? 0,
        timeMs,
        extras: {
          ...(this.dataIn?.extras ?? {}),
          reason: "user_exit",
          stats, // nhét toàn bộ payload chuẩn vào đây
        },
      };

      if (options.reportComplete) {
        options.reportComplete(payload);
        return;
      }

      if (options.fallbackSceneKey) {
        options.onLeave?.();
        this.scene.stop(KEY);
        this.scene.start(options.fallbackSceneKey);
      }
    }

    private startConfetti() {
      const rateMs = options.confetti?.rateMs ?? 100;
      this.confettiEvent = this.time.addEvent({
        delay: rateMs,
        loop: true,
        callback: () => {
          if (!this.scene.isActive()) return;
          const width = this.cameras.main.width;
          for (let i = 0; i < 3; i++) {
            this.createConfettiPiece(
              Phaser.Math.Between(0, width),
              -20,
              Phaser.Utils.Array.GetRandom(confettiColors),
              Phaser.Utils.Array.GetRandom(["circle", "rect"] as const)
            );
          }
        },
      });
    }

    private createConfettiPiece(
      x: number,
      y: number,
      color: number,
      shape: "circle" | "rect"
    ) {
      let confetti: Phaser.GameObjects.Arc | Phaser.GameObjects.Rectangle;

      if (shape === "circle") {
        confetti = this.add.circle(x, y, Phaser.Math.Between(4, 8), color, 1);
      } else {
        confetti = this.add.rectangle(
          x,
          y,
          Phaser.Math.Between(6, 12),
          Phaser.Math.Between(10, 20),
          color,
          1
        );
      }

      confetti.setDepth(999);
      confetti.setRotation((Phaser.Math.Between(0, 360) * Math.PI) / 180);

      const duration = Phaser.Math.Between(3000, 5000);
      const targetY = this.cameras.main.height + 50;
      const drift = Phaser.Math.Between(-100, 100);

      this.tweens.add({
        targets: confetti,
        y: targetY,
        x: x + drift,
        rotation: confetti.rotation + Phaser.Math.Between(2, 4) * Math.PI,
        duration,
        ease: "Linear",
        onComplete: () => confetti.destroy(),
      });

      this.tweens.add({
        targets: confetti,
        alpha: { from: 1, to: 0.3 },
        duration,
        ease: "Cubic.easeIn",
      });
    }

    private stopConfetti() {
      if (this.confettiEvent) {
        this.confettiEvent.remove(false);
        this.confettiEvent = undefined;
      }
    }
  };
}
