// -------------------- Envelope --------------------
export type MsgEnvelope<T = any> = {
  sdkVersion: string; // phiên bản SDK của message
  sessionId: string; // Hub cấp
  gameId: string;
  lessonId?: string;
  gameVersion?: string;
  source: "hub" | "game";
  type: string; // xem HostCommand / GameEvent
  payload?: T;
};

// -------------------- Message Types --------------------
export const MessageType = {
  // System handshake
  HELLO: "SYS:HELLO", // Game -> Hub: "I'm online"
  INIT: "CMD:INIT", // Hub -> Game: "Here's your context"

  // Game lifecycle commands (Hub -> Game)
  START: "CMD:START",
  PAUSE: "CMD:PAUSE",
  RESUME: "CMD:RESUME",
  RESIZE: "CMD:RESIZE",
  QUIT: "CMD:QUIT",
  SET_STATE: "CMD:SET_STATE",

  // Game events (Game -> Hub)
  READY: "EVT:READY",
  LOADING: "EVT:LOADING",
  SCORE_UPDATE: "EVT:SCORE_UPDATE",
  PROGRESS: "EVT:PROGRESS",
  COMPLETE: "EVT:COMPLETE",
  ERROR: "EVT:ERROR",
  REQUEST_SAVE: "EVT:REQUEST_SAVE",
  REQUEST_LOAD: "EVT:REQUEST_LOAD",
} as const;

// -------------------- Commands: Hub -> Game --------------------
export type HubCommand =
  | { type: "INIT"; payload: LaunchContext }
  | { type: "START" }
  | { type: "PAUSE" }
  | { type: "RESUME" }
  | { type: "RESIZE"; payload: { width: number; height: number; dpr: number } }
  | { type: "QUIT" }
  | { type: "SET_STATE"; payload: any };

export type LaunchContext = {
  // optional mềm để không block khi Hub chưa cấp
  sdkVersion?: string;
  playerId?: string;

  sessionId: string;
  lessonId?: string;
  gameId: string;
  gameVersion?: string;

  locale: string;
  difficulty?: string;
  seed?: number;

  launchToken?: string;

  profile?: Record<string, any>;

  sizeHint?: {
    width: number;
    height: number;
    devicePixelRatio?: number;
  };
  featureFlags?: Record<string, boolean>;
};

// -------------------- Events: Game -> Hub --------------------
export type GameEvent =
  | { type: "READY"; payload?: { capabilities?: string[] } }
  | { type: "LOADING"; payload: { progress: number } } // 0..1
  | { type: "SCORE_UPDATE"; payload: { score: number; delta?: number } }
  | { type: "PROGRESS"; payload: any } // snapshot nhỏ
  | {
      type: "COMPLETE";
      payload: { score: number; timeMs: number; extras?: any };
    }
  | {
      type: "ERROR";
      payload: { code: GameErrorCode; message: string; detail?: any };
    }
  | { type: "REQUEST_SAVE"; payload: any }
  | { type: "REQUEST_LOAD"; payload?: undefined };

export type GameErrorCode =
  | "BOOT_TIMEOUT"
  | "ASSET_LOAD_FAIL"
  | "RUNTIME_EXCEPTION"
  | "UNSUPPORTED_BROWSER";

// -------------------- Helpers --------------------
export function makeEnvelope<TPayload>(params: {
  sdkVersion: string;
  source: "hub" | "game";
  sessionId: string;
  gameId: string;
  lessonId?: string;
  gameVersion?: string;
  type: string;
  payload?: TPayload;
}): MsgEnvelope<TPayload> {
  return {
    sdkVersion: params.sdkVersion,
    source: params.source,
    sessionId: params.sessionId,
    gameId: params.gameId,
    lessonId: params.lessonId,
    gameVersion: params.gameVersion,
    type: params.type,
    payload: params.payload,
  };
}

export function estimateJsonBytes(value: unknown): number {
  // ASCII-safe estimate: JS string length ~ bytes for basic chars.
  // Good enough to enforce 16KB budget.
  try {
    return JSON.stringify(value).length;
  } catch {
    return Number.POSITIVE_INFINITY;
  }
}

export function isRecord(v: unknown): v is Record<string, unknown> {
  return typeof v === "object" && v !== null;
}

export function isValidEnvelope(v: unknown): v is MsgEnvelope<any> {
  if (!isRecord(v)) return false;

  if (typeof v.sdkVersion !== "string" || v.sdkVersion.length < 1) return false;
  if (v.source !== "hub" && v.source !== "game") return false;

  if (typeof v.sessionId !== "string" || v.sessionId.length < 1) return false;
  if (typeof v.gameId !== "string" || v.gameId.length < 1) return false;
  if (typeof v.lessonId !== "string" || v.lessonId.length < 1) return false;

  if (typeof v.type !== "string" || v.type.length < 1) return false;

  // if (typeof v.gameVersion !== 'string' || v.gameVersion.length < 1) return false;

  return true;
}

// Strict-ish runtime guards (optional dùng ở Hub/Game để tránh crash)
export function isHubCommandType(t: string): t is HubCommand["type"] {
  return (
    t === "INIT" ||
    t === "START" ||
    t === "PAUSE" ||
    t === "RESUME" ||
    t === "RESIZE" ||
    t === "QUIT" ||
    t === "SET_STATE"
  );
}

export function isGameEventType(t: string): t is GameEvent["type"] {
  return (
    t === "READY" ||
    t === "LOADING" ||
    t === "SCORE_UPDATE" ||
    t === "PROGRESS" ||
    t === "COMPLETE" ||
    t === "ERROR" ||
    t === "REQUEST_SAVE" ||
    t === "REQUEST_LOAD"
  );
}

export function clamp01(n: number): number {
  if (!Number.isFinite(n)) return 0;
  if (n < 0) return 0;
  if (n > 1) return 1;
  return n;
}

// ==================== Runtime Payload Validators ====================

export type ValidationResult<T> =
  | { ok: true; value: T }
  | { ok: false; error: string };

function err(msg: string): ValidationResult<never> {
  return { ok: false, error: msg };
}

function ok<T>(value: T): ValidationResult<T> {
  return { ok: true, value };
}

function isNumber(v: unknown): v is number {
  return typeof v === "number" && Number.isFinite(v);
}

function isString(v: unknown): v is string {
  return typeof v === "string";
}

function isBoolean(v: unknown): v is boolean {
  return typeof v === "boolean";
}

function getPath(obj: Record<string, unknown>, key: string): unknown {
  return obj[key];
}

export const MAX_MESSAGE_BYTES = 16 * 1024; // 16KB

export function validateMessageSize(envelope: unknown): ValidationResult<void> {
  const bytes = estimateJsonBytes(envelope);
  if (bytes > MAX_MESSAGE_BYTES) {
    return err(`payload_too_large: ${bytes} bytes > ${MAX_MESSAGE_BYTES}`);
  }
  return ok(undefined);
}

// ---------- LaunchContext (INIT.payload) ----------
export function validateLaunchContext(
  v: unknown
): ValidationResult<LaunchContext> {
  if (!isRecord(v)) return err("LaunchContext must be an object");

  const sessionId = getPath(v, "sessionId");
  if (!isString(sessionId) || sessionId.length < 1)
    return err("LaunchContext.sessionId must be a non-empty string");

  const lessonId = getPath(v, "lessonId");
  if (!isString(lessonId) || lessonId.length < 1)
    return err("LaunchContext.lessonId must be a non-empty string");

  const gameId = getPath(v, "gameId");
  if (!isString(gameId) || gameId.length < 1)
    return err("LaunchContext.gameId must be a non-empty string");

  const gameVersion = getPath(v, "gameVersion");
  if (!isString(gameVersion) || gameVersion.length < 1)
    return err("LaunchContext.gameVersion must be a non-empty string");

  const locale = getPath(v, "locale");
  if (!isString(locale) || locale.length < 1)
    return err("LaunchContext.locale must be a non-empty string");

  const sdkVersion = getPath(v, "sdkVersion");
  if (sdkVersion !== undefined && !isString(sdkVersion))
    return err("LaunchContext.sdkVersion must be a string");

  const playerId = getPath(v, "playerId");
  if (playerId !== undefined && !isString(playerId))
    return err("LaunchContext.playerId must be a string");

  const launchToken = getPath(v, "launchToken");
  if (launchToken !== undefined && !isString(launchToken))
    return err("LaunchContext.launchToken must be a string");

  const difficulty = getPath(v, "difficulty");
  if (difficulty !== undefined && !isString(difficulty))
    return err("LaunchContext.difficulty must be a string");

  const seed = getPath(v, "seed");
  if (seed !== undefined && !isNumber(seed))
    return err("LaunchContext.seed must be a number");

  const profile = getPath(v, "profile");
  if (profile !== undefined && !isRecord(profile))
    return err("LaunchContext.profile must be an object");

  const sizeHint = getPath(v, "sizeHint");
  if (sizeHint !== undefined) {
    if (!isRecord(sizeHint))
      return err("LaunchContext.sizeHint must be an object");
    const width = getPath(sizeHint, "width");
    const height = getPath(sizeHint, "height");
    const dpr = getPath(sizeHint, "devicePixelRatio");
    if (!isNumber(width) || width <= 0)
      return err("LaunchContext.sizeHint.width must be a positive number");
    if (!isNumber(height) || height <= 0)
      return err("LaunchContext.sizeHint.height must be a positive number");
    if (dpr !== undefined && (!isNumber(dpr) || dpr <= 0 || dpr > 8)) {
      return err("LaunchContext.sizeHint.devicePixelRatio must be (0..8]");
    }
  }

  const featureFlags = getPath(v, "featureFlags");
  if (featureFlags !== undefined) {
    if (!isRecord(featureFlags))
      return err("LaunchContext.featureFlags must be an object");
    for (const [k, val] of Object.entries(featureFlags)) {
      if (!isBoolean(val))
        return err(`LaunchContext.featureFlags['${k}'] must be boolean`);
    }
  }

  return ok({
    sdkVersion: sdkVersion as any,
    playerId: playerId as any,
    sessionId,
    lessonId,
    gameId,
    gameVersion,
    locale,
    difficulty: difficulty as any,
    seed: seed as any,
    launchToken: launchToken as any,
    profile: profile as any,
    sizeHint: sizeHint as any,
    featureFlags: featureFlags as any,
  });
}

// ---------- RESIZE.payload ----------
export function validateResizePayload(
  v: unknown
): ValidationResult<{ width: number; height: number; dpr: number }> {
  if (!isRecord(v)) return err("RESIZE.payload must be an object");

  const width = getPath(v, "width");
  const height = getPath(v, "height");
  const dpr = getPath(v, "dpr");

  if (!isNumber(width) || width <= 0)
    return err("RESIZE.payload.width must be a positive number");
  if (!isNumber(height) || height <= 0)
    return err("RESIZE.payload.height must be a positive number");
  if (!isNumber(dpr) || dpr <= 0 || dpr > 8)
    return err("RESIZE.payload.dpr must be (0..8]");

  return ok({ width, height, dpr });
}

// ---------- LOADING.payload ----------
export function validateLoadingPayload(
  v: unknown
): ValidationResult<{ progress: number }> {
  if (!isRecord(v)) return err("LOADING.payload must be an object");
  const progress = getPath(v, "progress");
  if (!isNumber(progress))
    return err("LOADING.payload.progress must be a number");
  return ok({ progress: clamp01(progress) });
}

// ---------- SCORE_UPDATE.payload ----------
export function validateScoreUpdatePayload(
  v: unknown
): ValidationResult<{ score: number; delta?: number }> {
  if (!isRecord(v)) return err("SCORE_UPDATE.payload must be an object");
  const score = getPath(v, "score");
  if (!isNumber(score))
    return err("SCORE_UPDATE.payload.score must be a number");

  const delta = getPath(v, "delta");
  if (delta !== undefined && !isNumber(delta))
    return err("SCORE_UPDATE.payload.delta must be a number");

  return ok({ score, delta: delta as any });
}

// ---------- COMPLETE.payload ----------
export function validateCompletePayload(
  v: unknown
): ValidationResult<{ score: number; timeMs: number; extras?: any }> {
  if (!isRecord(v)) return err("COMPLETE.payload must be an object");
  const score = getPath(v, "score");
  const timeMs = getPath(v, "timeMs");

  if (!isNumber(score)) return err("COMPLETE.payload.score must be a number");
  if (!isNumber(timeMs) || timeMs < 0)
    return err("COMPLETE.payload.timeMs must be a non-negative number");

  // extras: any (nhưng message size vẫn bị giới hạn 16KB)
  const extras = getPath(v, "extras");
  return ok({ score, timeMs, extras });
}

// ---------- ERROR.payload ----------
export function validateErrorPayload(
  v: unknown
): ValidationResult<{ code: GameErrorCode; message: string; detail?: any }> {
  if (!isRecord(v)) return err("ERROR.payload must be an object");

  const code = getPath(v, "code");
  const message = getPath(v, "message");
  const detail = getPath(v, "detail");

  const validCodes: GameErrorCode[] = [
    "BOOT_TIMEOUT",
    "ASSET_LOAD_FAIL",
    "RUNTIME_EXCEPTION",
    "UNSUPPORTED_BROWSER",
  ];
  if (!isString(code) || !validCodes.includes(code as GameErrorCode)) {
    return err(`ERROR.payload.code must be one of ${validCodes.join(", ")}`);
  }
  if (!isString(message) || message.length < 1)
    return err("ERROR.payload.message must be a non-empty string");

  return ok({ code: code as GameErrorCode, message, detail });
}

// ---------- Envelope + type-specific validation ----------
export type ValidatedIncoming =
  | { kind: "hubCommand"; command: HubCommand; envelope: MsgEnvelope<any> }
  | { kind: "gameEvent"; event: GameEvent; envelope: MsgEnvelope<any> };

export function validateIncomingEnvelope(
  v: unknown
): ValidationResult<MsgEnvelope<any>> {
  if (!isValidEnvelope(v)) return err("Invalid envelope");
  const sizeOk = validateMessageSize(v);
  if (!sizeOk.ok) return sizeOk;
  return ok(v);
}

/**
 * Parse + validate cụ thể dựa vào type.
 * - Dùng ở Hub: expect gameEvent
 * - Dùng ở Game: expect hubCommand
 */
export function parseHubCommandFromEnvelope(
  env: MsgEnvelope<any>
): ValidationResult<HubCommand> {
  const t = env.type;

  if (!isHubCommandType(t)) return err(`Unknown HubCommand type: ${t}`);

  switch (t) {
    case "INIT": {
      const res = validateLaunchContext(env.payload);
      if (!res.ok) return err(`INIT.payload invalid: ${res.error}`);
      // if (res.value.sessionId !== env.sessionId) {
      //   return err(`INIT.sessionId mismatch: envelope=${env.sessionId} payload=${res.value.sessionId}`);
      // }
      return ok({ type: "INIT", payload: res.value });
    }
    case "RESIZE": {
      const res = validateResizePayload(env.payload);
      if (!res.ok) return err(`RESIZE.payload invalid: ${res.error}`);
      return ok({ type: "RESIZE", payload: res.value });
    }
    case "START":
    case "PAUSE":
    case "RESUME":
    case "QUIT":
      return ok({ type: t } as HubCommand);
    case "SET_STATE": {
      return ok({ type: "SET_STATE", payload: env.payload });
    }
  }
}

export function parseGameEventFromEnvelope(
  env: MsgEnvelope<any>
): ValidationResult<GameEvent> {
  const t = env.type;

  if (!isGameEventType(t)) return err(`Unknown GameEvent type: ${t}`);

  switch (t) {
    case "READY": {
      // payload optional
      if (env.payload === undefined) return ok({ type: "READY" });
      if (!isRecord(env.payload))
        return err("READY.payload must be an object when provided");
      const caps = (env.payload as any).capabilities;
      if (caps !== undefined) {
        if (!Array.isArray(caps) || !caps.every((x) => typeof x === "string")) {
          return err("READY.payload.capabilities must be string[]");
        }
      }
      return ok({ type: "READY", payload: { capabilities: caps } });
    }

    case "LOADING": {
      const res = validateLoadingPayload(env.payload);
      if (!res.ok) return err(`LOADING.payload invalid: ${res.error}`);
      return ok({ type: "LOADING", payload: res.value });
    }

    case "SCORE_UPDATE": {
      const res = validateScoreUpdatePayload(env.payload);
      if (!res.ok) return err(`SCORE_UPDATE.payload invalid: ${res.error}`);
      return ok({ type: "SCORE_UPDATE", payload: res.value });
    }

    case "PROGRESS":
      // PROGRESS: any, chỉ enforce size + envelope
      return ok({ type: "PROGRESS", payload: env.payload });

    case "COMPLETE": {
      const res = validateCompletePayload(env.payload);
      if (!res.ok) return err(`COMPLETE.payload invalid: ${res.error}`);
      return ok({ type: "COMPLETE", payload: res.value });
    }

    case "ERROR": {
      const res = validateErrorPayload(env.payload);
      if (!res.ok) return err(`ERROR.payload invalid: ${res.error}`);
      return ok({ type: "ERROR", payload: res.value });
    }

    case "REQUEST_SAVE":
      return ok({ type: "REQUEST_SAVE", payload: env.payload });
    case "REQUEST_LOAD":
      return ok({ type: "REQUEST_LOAD" });
  }
}
